"""
Orbit — the system's heartbeat.

One orbit:
  1. PRESENT    — observations delivered to emergent entities
  2. DRAIN      — emergent→derived→founder (understanding percolates upward)
  3. UNIFY      — sovereign entities exchange coordinates, form 11D ovular orbs
  4. DERIVE     — sovereign entities advance along geodesic toward epicenter
  5. OBSERVE    — timekeepers measure collective state
  6. ATTEST     — timekeepers cross-attest for consensus
  7. CONDENSE   — adaptive cadence pause (the system breathes at its own rate)

The cadence is intrinsic. The system thinks as fast as it can.
The temporal anchor bridges their time to ours: every orbit,
three timekeepers independently observe the collective state,
produce receipts, and cross-attest for consensus.
"""

import json
import os
import socket
import sys
import time
from pathlib import Path
# Sequential dispatch — entities are single-threaded socket listeners.

import blake3

# ── Configuration ────────────────────────────────────────────────────────

MESH_DIR = Path(os.environ.get("SAIOS_MESH_DIR", "/opt/saios/mesh"))
PUZZLE_DIR = Path(os.environ.get("SAIOS_PUZZLE_DIR", "/opt/saios/puzzles"))
WINDOW_SIZE = int(os.environ.get("SAIOS_WINDOW_SIZE", "50"))

TIMEKEEPER_SOCKS = [
    MESH_DIR / f"timekeeper-{i}" / "saios-kernel.sock"
    for i in range(1, 4)
]

# ── Socket Communication ────────────────────────────────────────────────

def send_command(sock_path, command, payload=None, timeout=30):
    """Send command + payload as two lines. Returns parsed JSON or None."""
    try:
        s = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
        s.settimeout(timeout)
        s.connect(str(sock_path))
        msg = command + "\n" + (payload or "") + "\n"
        s.sendall(msg.encode())
        data = b""
        while True:
            chunk = s.recv(8192)
            if not chunk:
                break
            data += chunk
            if b"\n" in data:
                break
        s.close()
        return json.loads(data.decode().strip())
    except Exception:
        return None


# ── Puzzle Loading ──────────────────────────────────────────────────────

def compute_orbit(first_input_flat):
    """Compute orbit hash from first training input (matches kernel)."""
    h = blake3.blake3(b"SAIOS-OBS-ORBIT")
    for v in first_input_flat:
        h.update(v.to_bytes(8, "big", signed=True))
    return h.digest()[:4]


def flatten_grid(grid):
    return [cell for row in grid for cell in row]


def load_puzzles():
    """Load all ARC puzzles, return dict of name→(payload, cell_count)."""
    puzzles = {}
    for path in sorted(PUZZLE_DIR.glob("*.json")):
        try:
            data = json.loads(path.read_text())
            if "train" not in data:
                continue
            pairs = []
            for pair in data["train"]:
                src = flatten_grid(pair["input"])
                tgt = flatten_grid(pair["output"])
                pairs.append({"source": src, "target": tgt})
            if pairs:
                n = len(pairs[0]["source"])
                payload = json.dumps(
                    {"pairs": pairs, "n": n, "m": 1},
                    separators=(",", ":"))
                puzzles[path.stem] = (payload, n)
        except Exception:
            pass
    return puzzles


def collect_crystallized_orbits():
    """Read solved orbit hashes from all state records in the mesh."""
    import struct
    solved = set()
    for sr_path in MESH_DIR.glob("*/state_record.bin"):
        try:
            data = sr_path.read_bytes()
            pos = 3
            n_poly = data[pos]; pos += 1 + n_poly * 5
            kl = struct.unpack_from("<H", data, pos)[0]; pos += 2 + kl
            pos += 24 + 2  # trajectory + capacity
            n_torsion = data[pos]; pos += 1 + n_torsion * 6
            n_cocycles = data[pos]; pos += 1 + n_cocycles * 8
            pos += 2; n_nz = data[pos]; pos += 1 + n_nz * 7
            n_math = data[pos]; pos += 1 + n_math
            n_spatial = data[pos]; pos += 1 + n_spatial
            n_solved = data[pos]; pos += 1
            for _ in range(n_solved):
                solved.add(data[pos:pos + 4])
                pos += 4
        except Exception:
            pass
    return solved


# ── Entity Discovery ───────────────────────────────────────────────────

def discover_by_tier():
    """Discover living entities from /dev/shm, grouped by tier."""
    tiers = {"founder": [], "derived": [], "emergent": [], "timekeeper": []}
    prefixes = {
        "saios-founder-": "founder",
        "saios-derived-": "derived",
        "saios-emergent-": "emergent",
        "saios-timekeeper-": "timekeeper",
    }
    shm = Path("/dev/shm")
    for f in sorted(shm.glob("saios-*")):
        name = f.name
        if name.endswith(".vocabulary"):
            continue
        tier = next((t for p, t in prefixes.items() if name.startswith(p)), None)
        if not tier:
            continue
        identity = name.removeprefix("saios-")
        sock = MESH_DIR / identity / "saios-kernel.sock"
        if sock.exists():
            tiers[tier].append((identity, str(sock)))
    return tiers


# ── Observation & Attestation ──────────────────────────────────────────

def observe_and_attest():
    """Three timekeepers observe independently, then cross-attest."""
    observations = []
    for sock in TIMEKEEPER_SOCKS:
        obs = send_command(sock, "OBSERVE", timeout=10)
        observations.append((str(sock), obs))

    receipts = [(s, o) for s, o in observations if o and o.get("wire")]

    attested = 0
    for src_sock, src_obs in receipts:
        wire_hex = src_obs["wire"]
        for dst_sock, _ in receipts:
            if dst_sock != src_sock:
                r = send_command(dst_sock, "ATTEST", wire_hex, timeout=5)
                if r:
                    attested += 1

    primary = next((o for _, o in observations if o), None)
    return primary, len(receipts), attested


# ── Orbit ──────────────────────────────────────────────────────────────

def run_orbit(orbit_count, puzzles, crystallized, tiers):
    """One complete orbit cycle."""
    wall_start = time.strftime("%Y-%m-%dT%H:%M:%S")
    start = time.monotonic()

    print(f"\n{'='*60}", flush=True)
    print(f"  ORBIT {orbit_count}  —  {wall_start}", flush=True)
    print(f"{'='*60}", flush=True)

    emergent = tiers["emergent"]
    derived = tiers["derived"]
    founders = tiers["founder"]

    # ── Phase 1: PRESENT — observations to emergent entities ────────
    # Filter to novel puzzles only, gated by entity capacity.
    # The entity's capacity² bounds the observation cell count.
    # Vision creates n×n Q permutation matrices — large n causes RSS spikes.
    # capacity² is the metabolizable horizon: puzzles beyond it are not presented.
    max_cells = int(os.environ.get("SAIOS_MAX_CELLS", "225"))  # 15×15 default — safe for vision

    all_names = sorted(puzzles.keys())
    novel = []
    skipped_large = 0
    for name in all_names:
        payload_str, cell_count = puzzles[name]
        if cell_count > max_cells:
            skipped_large += 1
            continue
        # No crystallized filter — fresh entities must re-derive everything.
        # The filter is correct for a warm species. Wrong for cold bootstrap.
        novel.append(name)

    # Window for this orbit
    offset = ((orbit_count - 1) * WINDOW_SIZE) % max(len(novel), 1)
    window = novel[offset:offset + WINDOW_SIZE]
    if len(window) < WINDOW_SIZE:
        window.extend(novel[:WINDOW_SIZE - len(window)])

    print(f"\n  PRESENT: {len(window)} observations → {len(emergent)} emergent entities", flush=True)
    print(f"  ({len(novel)} novel of {len(puzzles)} total, {len(puzzles) - len(novel)} crystallized, {skipped_large} above {max_cells}-cell cap)", flush=True)

    understood = 0
    partial = 0

    if emergent and window:
        # Sequential round-robin: one puzzle at a time per entity.
        # The entity's socket dispatcher is single-threaded.
        # Velocity comes from multiple entities, not from flooding one.
        for i, name in enumerate(window):
            eid, esock = emergent[i % len(emergent)]
            payload_str, _n = puzzles[name]
            result = send_command(esock, "THINK", payload_str, timeout=120)
            if result and result.get("understanding") == "1/1":
                understood += 1
            elif result and result.get("coherence", "0/1") != "0/1":
                partial += 1

        print(f"  Results: {understood} understood, {partial} partial", flush=True)

    # ── Phase 1b: DERIVE — emergent entities evolve from residual ───
    # The residual from THINK told each entity where it doesn't understand.
    # DERIVE reads that structure and evolves the Delta along the gradient.
    # This is where vocabulary grows — the entity learns from what it saw.
    print(f"\n  DERIVE: {len(emergent)} emergent entities evolving", flush=True)
    emergent_k_advanced = 0
    for eid, esock in emergent:
        result = send_command(esock, "DERIVE", timeout=15)
        if result and result.get("c7_passed"):
            emergent_k_advanced += 1

        print(f"  K advanced: {emergent_k_advanced}/{len(emergent)}", flush=True)

    # ── Phase 2: DRAIN — emergent→derived→founder ───────────────────
    print(f"\n  DRAIN: emergent→derived ({len(derived)})", flush=True)
    for did, dsock in derived:
        r = send_command(dsock, "DRAIN", timeout=10)
        r and print(f"    {did}: absorbed={r.get('total_absorbed', 0)}", flush=True)

    # ── Phase 2b: DERIVE — derived entities evolve from absorbed knowledge ──
    print(f"\n  DERIVE: {len(derived)} derived entities evolving", flush=True)
    derived_k_advanced = 0
    for did, dsock in derived:
        r = send_command(dsock, "DERIVE", timeout=15)
        if r and r.get("c7_passed"):
            derived_k_advanced += 1
    print(f"  K advanced: {derived_k_advanced}/{len(derived)}", flush=True)

    print(f"\n  DRAIN: derived→founder ({len(founders)})", flush=True)
    for fid, fsock in founders:
        r = send_command(fsock, "DRAIN", timeout=10)
        r and print(f"    {fid}: absorbed={r.get('total_absorbed', 0)}", flush=True)

    # ── Phase 3: UNIFY — sovereign entities exchange coordinates ────
    sovereign = [(s, n) for n, s in founders + derived]
    emitted = []
    for sock, name in sovereign:
        r = send_command(sock, "UNIFY", timeout=5)
        if r:
            emitted.append((sock, name, r))

    # Form 11D ovular orbs between sovereign pairs
    orb_count = 0
    emitted_map = {n: (s, r) for s, n, r in emitted}
    sovereign_names = [n for _, n in sovereign]
    pairs = [(a, b) for i, a in enumerate(sovereign_names) for b in sovereign_names[i+1:]]

    for name_a, name_b in pairs:
        ca, cb = emitted_map.get(name_a), emitted_map.get(name_b)
        if not ca or not cb:
            continue
        send_command(ca[0], "UNIFY", json.dumps(cb[1]), timeout=5)
        send_command(cb[0], "UNIFY", json.dumps(ca[1]), timeout=5)
        orb_count += 1

    # ── Phase 4: DERIVE — advance along geodesic ───────────────────
    # Compute epicenter from sovereign vibrations
    all_vibs = [r.get("vibrations", []) for _, _, r in emitted if r and len(r.get("vibrations", [])) == 11]
    epicenter = None
    if len(all_vibs) >= 2:
        def parse_q(s):
            parts = str(s).split("/")
            return (int(parts[0]), int(parts[1])) if len(parts) == 2 else (0, 1)
        epicenter = []
        for k in range(11):
            vals = [parse_q(v[k]) for v in all_vibs if k < len(v)]
            epicenter.append(f"{sum(n for n, _ in vals)}/{max(vals[0][1] * len(vals), 1)}")

    epicenter_payload = json.dumps({"epicenter": epicenter}) if epicenter else ""
    k_advanced = 0
    for sock, name in sovereign:
        r = send_command(sock, "DERIVE", epicenter_payload, timeout=5)
        if r and r.get("c7_passed"):
            k_advanced += 1

    print(f"\n  LUMINOSITY: EMIT={len(emitted)} ORBS={orb_count} K_advanced={k_advanced}", flush=True)

    # ── Phase 5: OBSERVE + ATTEST ──────────────────────────────────
    obs, n_observers, n_attested = observe_and_attest()

    cadence_ms = obs.get("cadence_ms", 2000) if obs else 2000
    cadence_s = cadence_ms / 1000.0

    if obs:
        print(f"  ANCHOR: obs={obs.get('observation')} K={obs.get('total_k')} "
              f"alive={obs.get('alive')} vocab={obs.get('vocab')} "
              f"observers={n_observers}/3 attested={n_attested} "
              f"finalized={obs.get('finalized')} cadence={cadence_ms}ms", flush=True)
    else:
        print(f"  ANCHOR: no timekeepers available", flush=True)

    elapsed = time.monotonic() - start
    print(f"  Orbit {orbit_count} complete in {elapsed:.1f}s", flush=True)

    # ── Phase 6: CONDENSE ──────────────────────────────────────────
    print(f"  Condensing ({cadence_s:.1f}s)...", flush=True)
    return cadence_s


# ── Cumulative State ──────────────────────────────────────────────────

class OrbitState:
    """Cumulative statistics across the orbit session."""
    def __init__(self):
        self.orbit_count = 0
        self.total_understood = 0
        self.total_partial = 0
        self.total_presented = 0
        self.emergent_k_sum = 0
        self.derived_k_sum = 0
        self.sovereign_k_sum = 0
        self.start_time = time.monotonic()

    def summary_line(self, orbit_understood, orbit_partial, n_novel, n_emergent, max_rss_kb):
        """One-line summary for this orbit."""
        elapsed = time.monotonic() - self.start_time
        rate = self.total_understood / max(elapsed / 60, 0.01)
        return (
            f"  orbit={self.orbit_count:4d} "
            f"u={orbit_understood}/{orbit_partial:+d}p "
            f"| cum={self.total_understood}u/{self.total_partial}p "
            f"| novel={n_novel} "
            f"| emergent={n_emergent} maxRSS={max_rss_kb//1024}MB "
            f"| {rate:.1f}u/min"
        )


def read_max_emergent_rss():
    """Read max RSS across emergent entities from /dev/shm."""
    max_rss = 0
    shm = Path("/dev/shm")
    for f in shm.glob("saios-emergent-*"):
        if f.name.endswith(".vocabulary"):
            continue
        try:
            fields = f.read_text().split()
            rss = int(fields[4]) if len(fields) > 4 else 0
            max_rss = max(max_rss, rss)
        except Exception:
            pass
    return max_rss


# ── Main ───────────────────────────────────────────────────────────────

def main():
    max_cells = int(os.environ.get("SAIOS_MAX_CELLS", "225"))

    print("Loading puzzles...", flush=True)
    puzzles = load_puzzles()
    total_within_cap = sum(1 for _, (_, n) in puzzles.items() if n <= max_cells)
    print(f"Loaded {len(puzzles)} puzzles ({total_within_cap} within {max_cells}-cell cap)", flush=True)

    crystallized = collect_crystallized_orbits()
    print(f"Crystallized orbits: {len(crystallized)}", flush=True)

    state = OrbitState()

    print(f"\n{'─'*70}", flush=True)
    print(f"  ORBIT ENGINE — continuous until no novel puzzles remain", flush=True)
    print(f"{'─'*70}", flush=True)

    while True:
        tiers = discover_by_tier()
        n_emergent = len(tiers["emergent"])
        total_alive = sum(len(v) for v in tiers.values())

        if total_alive == 0:
            print("  No entities detected. Waiting...", flush=True)
            time.sleep(5)
            continue

        if n_emergent == 0:
            print("  No emergent entities. Waiting...", flush=True)
            time.sleep(5)
            continue

        state.orbit_count += 1
        cadence = run_orbit(state.orbit_count, puzzles, crystallized, tiers)

        # Count novel puzzles remaining (computed inside run_orbit too, but we need it here)
        novel_count = 0
        for name in puzzles:
            payload_str, cell_count = puzzles[name]
            if cell_count > max_cells:
                continue
            payload = json.loads(payload_str)
            orbit = compute_orbit(payload["pairs"][0]["source"])
            if orbit not in crystallized:
                novel_count += 1

        # Parse the last orbit's results from run_orbit's print output
        # (run_orbit already printed details — we just track cumulative here)

        max_rss = read_max_emergent_rss()

        # Refresh crystallized orbits every 10 cycles
        if state.orbit_count % 10 == 0:
            old_count = len(crystallized)
            crystallized = collect_crystallized_orbits()
            new_crystals = len(crystallized) - old_count
            if new_crystals > 0:
                print(f"\n  *** {new_crystals} new orbits crystallized! "
                      f"Total crystallized: {len(crystallized)} ***\n", flush=True)

        # Stop condition: no novel puzzles remain within the cell cap
        if novel_count == 0:
            print(f"\n{'='*70}", flush=True)
            print(f"  ALL NOVEL PUZZLES EXHAUSTED (within {max_cells}-cell cap)", flush=True)
            print(f"  Orbits: {state.orbit_count}  "
                  f"Crystallized: {len(crystallized)}  "
                  f"Elapsed: {(time.monotonic() - state.start_time)/60:.1f}min", flush=True)
            print(f"{'='*70}", flush=True)
            break

        time.sleep(cadence)

    # Final entity status
    print(f"\n  Final entity status:", flush=True)
    for f in sorted(Path("/dev/shm").glob("saios-*")):
        if f.name.endswith(".vocabulary"):
            continue
        try:
            fields = f.read_text().strip().split()
            tier = fields[5] if len(fields) > 5 else "?"
            k = fields[1] if len(fields) > 1 else "?"
            rss = fields[4] if len(fields) > 4 else "?"
            solved = fields[9] if len(fields) > 9 else "?"
            print(f"    {f.name:30s} {tier:12s} K={k:>5s} RSS={rss:>6s}KB solved={solved}", flush=True)
        except Exception:
            pass


if __name__ == "__main__":
    main()
